import {
  Switch as SwitchPrimitive,
  SwitchContext,
  useSwitch,
  useSwitchContext,
} from '@ark-ui/react/switch';
import { clsx } from 'clsx';
import type { ComponentProps, ComponentRef, ReactElement, ReactNode } from 'react';
import { Children, cloneElement, forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './Switch.module.css';

type SwitchSize = 'xs' | 'sm' | 'md' | 'lg' | 'xl';
type SwitchRootProps = ComponentProps<typeof SwitchPrimitive.Root> & { size?: SwitchSize };
type SwitchRootProviderProps = ComponentProps<typeof SwitchPrimitive.RootProvider> & {
  size?: SwitchSize;
};

const SwitchRoot = forwardRef<ComponentRef<typeof SwitchPrimitive.Root>, SwitchRootProps>(
  function SwitchRoot({ asChild, children, className, size = 'md', ...props }, ref) {
    return (
      <SwitchPrimitive.Root
        ref={ref}
        asChild={asChild}
        data-slot="switch-root"
        data-size={size}
        className={clsx(styles.root, normalizeClassName(className))}
        {...props}
      >
        {withHiddenInput(children, asChild)}
      </SwitchPrimitive.Root>
    );
  },
);

const SwitchRootProvider = forwardRef<
  ComponentRef<typeof SwitchPrimitive.RootProvider>,
  SwitchRootProviderProps
>(function SwitchRootProvider({ asChild, children, className, size = 'md', ...props }, ref) {
  return (
    <SwitchPrimitive.RootProvider
      ref={ref}
      asChild={asChild}
      data-slot="switch-root-provider"
      data-size={size}
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    >
      {withHiddenInput(children, asChild)}
    </SwitchPrimitive.RootProvider>
  );
});

const SwitchControl = forwardRef<
  ComponentRef<typeof SwitchPrimitive.Control>,
  ComponentProps<typeof SwitchPrimitive.Control>
>(function SwitchControl({ className, children, ...props }, ref) {
  return (
    <SwitchPrimitive.Control
      ref={ref}
      data-slot="switch-control"
      className={clsx(styles.control, normalizeClassName(className))}
      {...props}
    >
      {children ?? <SwitchThumb />}
    </SwitchPrimitive.Control>
  );
});

const SwitchThumb = forwardRef<
  ComponentRef<typeof SwitchPrimitive.Thumb>,
  ComponentProps<typeof SwitchPrimitive.Thumb>
>(function SwitchThumb({ className, ...props }, ref) {
  return (
    <SwitchPrimitive.Thumb
      ref={ref}
      data-slot="switch-thumb"
      className={clsx(styles.thumb, normalizeClassName(className))}
      {...props}
    />
  );
});

const SwitchLabel = forwardRef<
  ComponentRef<typeof SwitchPrimitive.Label>,
  ComponentProps<typeof SwitchPrimitive.Label>
>(function SwitchLabel({ className, ...props }, ref) {
  return (
    <SwitchPrimitive.Label
      ref={ref}
      data-slot="switch-label"
      className={clsx(styles.label, normalizeClassName(className))}
      {...props}
    />
  );
});

function withHiddenInput(children: ReactNode, asChild?: boolean) {
  const hiddenInput = <SwitchPrimitive.HiddenInput data-slot="switch-hidden-input" />;

  if (!asChild) {
    return (
      <>
        {children}
        {hiddenInput}
      </>
    );
  }

  const child = Children.only(children) as ReactElement<{ children?: ReactNode }>;

  return cloneElement(child, {}, child.props.children, hiddenInput);
}

const Switch = Object.assign(SwitchRoot, {
  Root: SwitchRoot,
  RootProvider: SwitchRootProvider,
  Control: SwitchControl,
  Thumb: SwitchThumb,
  Label: SwitchLabel,
  Context: SwitchContext,
});

export { Switch, useSwitch, useSwitchContext };
export type { SwitchRootProps, SwitchRootProviderProps, SwitchSize };

@layer moduix.components {
  .root {
    display: inline-flex;
    align-items: center;
    gap: var(--moduix-switch-gap, var(--moduix-spacing-2));
    width: fit-content;
    vertical-align: middle;
    cursor: pointer;

    &[data-disabled],
    &[data-readonly] {
      cursor: default;
    }

    &[data-disabled] {
      opacity: var(--moduix-switch-disabled-opacity, var(--moduix-opacity-disabled));
    }
  }

  .control {
    box-sizing: border-box;
    position: relative;
    display: inline-flex;
    flex-shrink: 0;
    align-items: center;
    width: var(--moduix-switch-width, 3rem);
    height: var(--moduix-switch-height, var(--moduix-size-xs));
    --moduix-switch-thumb-translate-default: calc(
      var(--moduix-switch-width, 3rem) - var(--moduix-switch-thumb-size, var(--moduix-spacing-5)) -
        (var(--moduix-switch-padding, var(--moduix-spacing-0-5)) * 2) -
        (var(--moduix-switch-border-width, var(--moduix-border-width-sm)) * 2)
    );
    border: var(--moduix-switch-border-width, var(--moduix-border-width-sm)) solid
      var(--moduix-switch-border-color, var(--moduix-color-border));
    border-radius: var(--moduix-switch-radius, var(--moduix-radius-full));
    padding: var(--moduix-switch-padding, var(--moduix-spacing-0-5));
    background-color: var(--moduix-switch-bg, var(--moduix-color-muted));
    outline: 0;
    line-height: 0;
    user-select: none;
    transition:
      background-color var(--moduix-switch-transition, var(--moduix-transition-default)),
      border-color var(--moduix-switch-transition, var(--moduix-transition-default)),
      opacity var(--moduix-switch-transition, var(--moduix-transition-default));

    &[data-state='checked'] {
      border-color: var(--moduix-switch-border-color-checked, var(--moduix-color-primary));
      background-color: var(--moduix-switch-bg-checked, var(--moduix-color-primary));
    }

    &[data-focus-visible] {
      outline: var(
          --moduix-switch-focus-ring-width,
          var(--moduix-focus-ring-inset-width, var(--moduix-border-width-sm))
        )
        solid var(--moduix-switch-focus-ring-color, var(--moduix-color-ring));
      outline-offset: var(--moduix-switch-focus-ring-offset, var(--moduix-border-width-sm));
    }

    @media (hover: hover) {
      &[data-state='unchecked'][data-hover]:not([data-readonly], [data-disabled]) {
        background-color: var(--moduix-switch-bg-hover, var(--moduix-color-accent));
      }

      &[data-state='checked'][data-hover]:not([data-readonly], [data-disabled]) {
        background-color: var(
          --moduix-switch-bg-checked-hover,
          var(--moduix-switch-bg-checked, var(--moduix-color-primary))
        );
      }
    }
  }

  .root[data-size='xs'] .control {
    --moduix-switch-width: var(--moduix-switch-width-xs, 1.75rem);
    --moduix-switch-height: var(--moduix-switch-height-xs, 1rem);
    --moduix-switch-thumb-size: var(--moduix-switch-thumb-size-xs, var(--moduix-spacing-3));
  }

  .root[data-size='sm'] .control {
    --moduix-switch-width: var(--moduix-switch-width-sm, 2.25rem);
    --moduix-switch-height: var(--moduix-switch-height-sm, 1.25rem);
    --moduix-switch-thumb-size: var(--moduix-switch-thumb-size-sm, var(--moduix-spacing-4));
  }

  .root[data-size='md'] .control {
    --moduix-switch-width: var(--moduix-switch-width-md, 2.75rem);
    --moduix-switch-height: var(--moduix-switch-height-md, var(--moduix-size-xs));
    --moduix-switch-thumb-size: var(--moduix-switch-thumb-size-md, var(--moduix-spacing-5));
  }

  .root[data-size='lg'] .control {
    --moduix-switch-width: var(--moduix-switch-width-lg, 3.25rem);
    --moduix-switch-height: var(--moduix-switch-height-lg, 1.75rem);
    --moduix-switch-thumb-size: var(--moduix-switch-thumb-size-lg, var(--moduix-size-xs));
  }

  .root[data-size='xl'] .control {
    --moduix-switch-width: var(--moduix-switch-width-xl, 3.75rem);
    --moduix-switch-height: var(--moduix-switch-height-xl, var(--moduix-size-sm));
    --moduix-switch-thumb-size: var(--moduix-switch-thumb-size-xl, var(--moduix-spacing-7));
  }

  .thumb {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: var(--moduix-switch-thumb-size, var(--moduix-spacing-5));
    height: var(--moduix-switch-thumb-size, var(--moduix-spacing-5));
    border: var(--moduix-switch-thumb-border-width, 0) solid
      var(--moduix-switch-thumb-border-color, transparent);
    border-radius: var(--moduix-switch-thumb-radius, var(--moduix-radius-full));
    background-color: var(
      --moduix-switch-thumb-bg-unchecked,
      var(--moduix-switch-thumb-bg, var(--moduix-color-background))
    );
    color: var(
      --moduix-switch-thumb-color-unchecked,
      var(--moduix-switch-thumb-color, var(--moduix-color-muted))
    );
    box-shadow: var(--moduix-switch-thumb-shadow, var(--moduix-shadow-sm));
    transform: translateX(0);
    transition:
      transform
        var(
          --moduix-switch-thumb-transition,
          var(--moduix-switch-transition, var(--moduix-transition-default))
        ),
      background-color var(--moduix-switch-transition, var(--moduix-transition-default)),
      color var(--moduix-switch-transition, var(--moduix-transition-default));

    &[data-state='checked'] {
      background-color: var(
        --moduix-switch-thumb-bg-checked,
        var(--moduix-switch-thumb-bg, var(--moduix-color-primary-foreground))
      );
      color: var(
        --moduix-switch-thumb-color-checked,
        var(--moduix-switch-thumb-color, var(--moduix-color-primary))
      );
      transform: translateX(
        var(--moduix-switch-thumb-translate, var(--moduix-switch-thumb-translate-default))
      );
    }

    & > svg {
      width: var(--moduix-switch-thumb-icon-size, 65%);
      height: var(--moduix-switch-thumb-icon-size, 65%);
      flex-shrink: 0;
    }
  }

  .label {
    color: var(--moduix-switch-label-color, var(--moduix-color-foreground));
    font-size: var(--moduix-switch-label-font-size, var(--moduix-text-sm));
    font-weight: var(--moduix-switch-label-font-weight, var(--moduix-weight-medium));
    line-height: var(--moduix-switch-label-line-height, var(--moduix-line-height-text-sm));
    user-select: none;
  }
}
